import type { Metadata } from "next"
import PropertyListing from "./PropertyListing"

export const metadata: Metadata = {
  title: "グランメゾン目黒 303号室 | 賃貸物件詳細・内見予約",
  description:
    "目黒駅徒歩8分・南向きの1LDK賃貸物件の詳細ページ。物件ヘッダ（物件名・所在地・最寄駅・賃料・間取り・専有面積、お気に入り、募集状況バッジ）の下に、写真ギャラリーと間取り図、賃料・初期費用の内訳（賃料/管理費/敷金/礼金/仲介手数料/保証料/鍵交換 → 初期費用合計）、物件概要（間取り/専有面積/築年月/構造/所在階/向き/入居可能日/取引態様/契約期間/更新）、設備・条件（present/absentが明確なアメニティ一覧）、周辺・アクセス（最寄駅・徒歩分＋地図）、空室状況を掲載。内見予約は日付（カレンダー、空き枠のない日と過去日は選択不可）と時間枠（満枠は選択不可）を選んで予約でき、問い合わせフォーム（名前・連絡先・希望条件・メッセージ、必須項目バリデーションつき）から仲介担当へ連絡できる、入居希望者向けの賃貸ポータル物件詳細・内見予約画面。",
}

export default function PropertyListingPage() {
  return <PropertyListing />
}
